function testAggregation() public {
  // Test successful call
  Multicall3.Call[] memory calls = new Multicall3.Call[](1);
  calls[0] = Multicall3.Call(address(callee), abi.encodeWithSignature("getBlockHash(uint256)", block.number));
  (uint256 blockNumber, bytes[] memory returnData) = multicall.aggregate(calls);
  assertEq(blockNumber, block.number);
  assertEq(keccak256(returnData[0]), keccak256(abi.encodePacked(blockhash(block.number))));
}

function testUnsuccessfulAggregation() public {
  // Test unexpected revert
  Multicall3.Call[] memory calls = new Multicall3.Call[](2);
  calls[0] = Multicall3.Call(address(callee), abi.encodeWithSignature("getBlockHash(uint256)", block.number));
  calls[1] = Multicall3.Call(address(callee), abi.encodeWithSignature("thisMethodReverts()"));
  vm.expectRevert(bytes("Multicall3: call failed"));
  multicall.aggregate(calls);
}

function aggregate(Call[] calldata calls) public returns (uint256 blockNumber, bytes[] memory returnData) {
    blockNumber = block.number;
    returnData = new bytes[](calls.length);
    for (uint256 i = 0; i < calls.length; i++) {
        (bool success, bytes memory ret) = calls[i].target.call(calls[i].callData);
        require(success);
        returnData[i] = ret;
    }
}

function aggregate(Call[] calldata calls) public returns (uint256 blockNumber, bytes[] memory returnData) {
    blockNumber = block.number;
    returnData = new bytes[](calls.length);
    for (uint256 i = 0; i < calls.length; i++) {
        (bool success, bytes memory ret) = calls[i].target.call(calls[i].callData);
        require(success, "Multicall aggregate: call failed");
        returnData[i] = ret;
    }
}

function tryAggregate(bool requireSuccess, Call[] calldata calls) public returns (Result[] memory returnData) {
    returnData = new Result[](calls.length);
    for (uint256 i = 0; i < calls.length; i++) {
        (bool success, bytes memory ret) = calls[i].target.call(calls[i].callData);

        if (requireSuccess) {
            require(success, "Multicall2 aggregate: call failed");
        }

        returnData[i] = Result(success, ret);
    }
}

function safeTransfer(IERC20 token, address to, uint256 value) internal {
    require(address(token).code.length > 0, ErrorsLib.NO_CODE);

    (bool success, bytes memory returndata) =
        address(token).call(abi.encodeCall(IERC20Internal.transfer, (to, value)));
    require(success, ErrorsLib.TRANSFER_REVERTED);
    require(returndata.length == 0 || abi.decode(returndata, (bool)), ErrorsLib.TRANSFER_RETURNED_FALSE);
}

function safeTransferFrom(IERC20 token, address from, address to, uint256 value) internal {
    require(address(token).code.length > 0, ErrorsLib.NO_CODE);

    (bool success, bytes memory returndata) =
        address(token).call(abi.encodeCall(IERC20Internal.transferFrom, (from, to, value)));
    require(success, ErrorsLib.TRANSFER_FROM_REVERTED);
    require(returndata.length == 0 || abi.decode(returndata, (bool)), ErrorsLib.TRANSFER_FROM_RETURNED_FALSE);
}

function flashLoan(address token, uint256 assets, bytes calldata data) external {
    require(assets != 0, ErrorsLib.ZERO_ASSETS);

    emit EventsLib.FlashLoan(msg.sender, token, assets);

    IERC20(token).safeTransfer(msg.sender, assets);

    IMorphoFlashLoanCallback(msg.sender).onMorphoFlashLoan(assets, data);

    IERC20(token).safeTransferFrom(msg.sender, address(this), assets);
}

